/// Implements ChangeNotifier for reactive state management
/// Shared across all device-specific dashboard views
library;

import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import 'package:go_router/go_router.dart';
import '../../../navigation/app_router.dart';
import '../../../providers/inspection_provider.dart';

/// Dashboard screen state management using ChangeNotifier pattern
class DashboardState extends ChangeNotifier {
  // Service locator pattern for state access
  static DashboardState s(BuildContext context, [bool listen = false]) =>
      Provider.of<DashboardState>(context, listen: listen);

  // State variables
  bool _isLoading = false;
  String? _errorMessage;
  int _selectedIndex = 0;

  // Real inspection data from SQLite (offline-first)
  List<Map<String, dynamic>> _recentInspections = [];

  DashboardState() {
    _loadRecentInspections();
  }

  // Getters
  bool get isLoading => _isLoading;
  String? get errorMessage => _errorMessage;
  int get selectedIndex => _selectedIndex;
  List<Map<String, dynamic>> get recentInspections => _recentInspections;

  /// Load recent inspections from SQLite database
  Future<void> _loadRecentInspections() async {
    try {
      final database = InspectionProvider.instance.database;
      if (database == null) {
        debugPrint('Database not initialized');
        _recentInspections = [];
        return;
      }

      // Query inspections from SQLite
      final results = await database.query(
        'inspections',
        orderBy: 'created_at DESC',
        limit: 10,
      );

      _recentInspections = results.map((row) {
        return {
          'id': row['id'] as String,
          'title': 'Inspection ${(row['id'] as String).substring(0, 8)}',
          'date': DateTime.parse(row['created_at'] as String),
          'status': row['status'] as String,
        };
      }).toList();

      debugPrint('Loaded ${_recentInspections.length} recent inspections from SQLite');
      notifyListeners();
    } catch (e) {
      debugPrint('Failed to load recent inspections: $e');
      _recentInspections = [];
    }
  }

  /// Set selected navigation index
  void setSelectedIndex(int index) {
    _selectedIndex = index;
    notifyListeners();
  }

  /// Clear error message
  void clearError() {
    _errorMessage = null;
    notifyListeners();
  }

  /// Refresh dashboard data from SQLite
  Future<void> refreshData() async {
    _isLoading = true;
    _errorMessage = null;
    notifyListeners();

    try {
      await _loadRecentInspections();
      debugPrint('Dashboard data refreshed - ${_recentInspections.length} inspections loaded');
    } catch (e) {
      _errorMessage = 'Failed to refresh data: ${e.toString()}';
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  /// Navigate to new inspection
  void navigateToNewInspection(BuildContext context) {
    debugPrint('🚀 Navigating to new inspection screen');
    context.go(AppRoutes.newInspection);
  }

  /// Navigate to inspection details
  void navigateToInspectionDetails(BuildContext context, String inspectionId) {
    debugPrint('🚀 Navigating to inspection details: $inspectionId');
    context.go(AppRoutes.inspectionDetailRoute(inspectionId));
  }

  /// Navigate to choose client
  void navigateToChooseClient(BuildContext context) {
    debugPrint('🚀 Navigating to choose client screen');
    context.go(AppRoutes.chooseClient);
  }

  /// Navigate to truck templates
  void navigateToTruckTemplates(BuildContext context) {
    debugPrint('🚀 Navigating to truck templates screen');
    context.go(AppRoutes.truckTemplates);
  }

  /// Navigate to about screen
  void navigateToAbout(BuildContext context) {
    debugPrint('🚀 Navigating to about screen');
    context.go(AppRoutes.about);
  }
