  String _formatDateTime(DateTime dateTime) {
    final months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    final hour = dateTime.hour % 12 == 0 ? 12 : dateTime.hour % 12;
    final period = dateTime.hour < 12 ? 'AM' : 'PM';
    final minute = dateTime.minute.toString().padLeft(2, '0');
    return '${months[dateTime.month - 1]} ${dateTime.day}, ${dateTime.year} $hour:$minute $period';
  }

  bool _canProceed(NewInspectionState state) {
    switch (_currentStep) {
      case 0:
        return state.selectedClient != null;
      case 1:
        return state.selectedTemplate != null;
      case 2:
        return state.titleController.text.isNotEmpty;
      case 3:
        return state.canCreateInspection;
      default:
        return false;
    }
  }

  void _nextStep(NewInspectionState state) {
    if (_currentStep < 3) {
      _pageController.nextPage(
        duration: const Duration(milliseconds: 300),
        curve: Curves.easeInOut,
      );
    } else {
      // Create inspection
      state.createInspection().then((_) {
        if (context.mounted && state.errorMessage == null) {
          // Navigate to inspection details or list
          context.go('/inspections');
        }
      });
    }
  }

  void _previousStep() {
    if (_currentStep > 0) {
      _pageController.previousPage(
        duration: const Duration(milliseconds: 300),
        curve: Curves.easeInOut,
      );
    }
  }

  @override
  void dispose() {
    _pageController.dispose();
    super.dispose();
