/// PhotoCaptureScreen main widget with responsive design
/// Manages camera operations, photo capture, and gallery functionality
class PhotoCaptureScreen extends StatelessWidget {
  final String inspectionId;
  final String? fieldId;
  final String? fieldLabel;
  final String? sectionName;

  const PhotoCaptureScreen({
    super.key,
    required this.inspectionId,
    this.fieldId,
    this.fieldLabel,
    this.sectionName,
  });

  @override
  Widget build(BuildContext context) {
    return ChangeNotifierProvider(
      create: (context) => PhotoCaptureState(
        inspectionId: inspectionId,
        fieldId: fieldId,
        fieldLabel: fieldLabel,
        sectionName: sectionName,
      ),
      child: Consumer<PhotoCaptureState>(
        builder: (context, state, child) {
          // Handle camera error state
          if (state.cameraError != null) {
            return ScreenWrapper.error(
              title: 'Photo Capture',
              errorMessage: state.cameraError!,
              onRetry: () => state.retryInitialization(),
            );
          }

          // Handle camera initialization loading
          if (state.isInitializing || !state.isCameraInitialized) {
            return ScreenWrapper.loading(
              title: 'Initializing Camera',
            );
          }

          // Main responsive interface
          return ScreenWrapper(
            title: 'Photo Capture',
            showAppBar: true,
            padding: EdgeInsets.zero, // Camera preview needs full screen
            actions: [
              // Photo counter
              if (state.hasPhotos)
                Container(
                  margin: const EdgeInsets.only(right: 16),
                  padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
                  decoration: BoxDecoration(
                    color: Theme.of(context).colorScheme.primary,
                    borderRadius: BorderRadius.circular(16),
                  ),
                  child: Text(
                    '${state.capturedPhotos.length}',
                    style: Theme.of(context).textTheme.labelMedium?.copyWith(
                      color: Theme.of(context).colorScheme.onPrimary,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                ),
            ],
            child: Responsive(
              mobile: PhotoCaptureMobileView(inspectionId: inspectionId),
              tablet: PhotoCaptureTabletView(inspectionId: inspectionId),
              desktop: PhotoCaptureDesktopView(inspectionId: inspectionId),
            ),
          );
        },
      ),
    );
  }
}
