/// E2E Integration Tests for Form Validation UI (Story A.8)
/// Tests AC-A.8.6: E2E test for validation error display and progress indicator
void main() {
  TestWidgetsFlutterBinding.ensureInitialized();
  sqfliteFfiInit();

  group('Form Validation UI - Story A.8 (AC-A.8.6)', () {
    late Database database;
    final provider = InspectionProvider.instance;
    final validationService = ValidationService.instance;

    setUp(() async {
      database = await _openInMemoryDatabase();
      await provider.initialize(database);
    });

    tearDown(() async {
      await database.close();
      provider.resetForTests();
    });

    testWidgets('Validation errors display in red below fields', (tester) async {
      await tester.runAsync(() async {
        // Arrange: Create template with required field
        final template = _buildTemplateWithRequiredField();
        final templateVersionId = _randomId('template_version');

        await _seedTemplate(
          database,
          template,
          templateVersionId: templateVersionId,
        );

        await provider.startInspection(
          templateId: template.id,
          templateVersionId: templateVersionId,
          template: template,
        );

        final inspectionId = provider.currentInspection!.id;
        final formState = InspectionFormState();
        await formState.initialize(inspectionId);

        // Act: Fill field with invalid data (empty required field)
        formState.updateField('technician_name', ''); // Required field left empty

        // Assert: Error should be present
        expect(formState.errors.containsKey('technician_name'), true);
        expect(formState.errors['technician_name'], contains('required'));

        // Act: Fill field with valid data
        formState.updateField('technician_name', 'John Doe');

        // Assert: Error should clear
        expect(formState.errors.containsKey('technician_name'), false);

        formState.dispose();
      });
    });

    testWidgets('Progress indicator updates when fields are filled', (tester) async {
      await tester.runAsync(() async {
        // Arrange: Create template with 3 required fields
        final template = _buildTemplateWithMultipleRequiredFields();
        final templateVersionId = _randomId('template_version');

        await _seedTemplate(
          database,
          template,
          templateVersionId: templateVersionId,
        );

        await provider.startInspection(
