/// Query all inspections from SQLite
/// Returns list of inspection maps sorted by created_at DESC
Future<List<Map<String, dynamic>>> queryInspections(Database db, {String? customerId}) async {
  try {
    if (customerId != null) {
      return await db.query(
        'inspections',
        where: 'customer_id = ?',
        whereArgs: [customerId],
        orderBy: 'created_at DESC',
      );
    } else {
      return await db.query(
        'inspections',
        orderBy: 'created_at DESC',
      );
    }
  } catch (e) {
    print('Error querying inspections: $e');
    return [];
  }
}

/// Query a single inspection by ID
Future<Map<String, dynamic>?> queryInspectionById(Database db, String inspectionId) async {
  try {
    final results = await db.query(
      'inspections',
      where: 'id = ?',
      whereArgs: [inspectionId],
      limit: 1,
    );
    return results.isNotEmpty ? results.first : null;
  } catch (e) {
    print('Error querying inspection by ID: $e');
    return null;
  }
}

/// Query all published templates from SQLite
/// Returns list of template maps sorted by name
Future<List<Map<String, dynamic>>> queryTemplates(Database db, {String? customerId}) async {
  try {
    if (customerId != null) {
      return await db.query(
        'template_versions',
        where: 'status = ? AND customer_id = ?',
        whereArgs: ['published', customerId],
        orderBy: 'created_at DESC',
      );
    } else {
      return await db.query(
        'template_versions',
        where: 'status = ?',
        whereArgs: ['published'],
        orderBy: 'created_at DESC',
      );
    }
  } catch (e) {
    print('Error querying templates: $e');
    return [];
  }
}

/// Query all active customers from SQLite
/// Returns list of customer maps sorted by name
Future<List<Map<String, dynamic>>> queryCustomers(Database db) async {
  try {
    return await db.query(
      'customers',
      where: 'is_active = ?',
      whereArgs: [1], // SQLite uses 1 for true
      orderBy: 'name ASC',
    );
  } catch (e) {
    print('Error querying customers: $e');
    return [];
  }
}

