/// Schema Parser Service
/// Parses and validates JSON templates with all canonical field types
/// Implements AC 3.1A.1
class SchemaParser {
  static SchemaParser? _instance;
  static SchemaParser get instance {
    _instance ??= SchemaParser._internal();
    return _instance!;
  }

  SchemaParser._internal();

  /// Supported canonical field types from Epic 2 template builder
  static const List<String> supportedFieldTypes = [
    'text_field',
    'number_field',
    'dropdown_field',
    'multi_select_field', // Story A.2: Added for AC-A.2.2 (14 field types)
    'date_field',
    'time_field', // Story A.2: Added for AC-A.2.2 (14 field types)
    'photo_field',
    'signature_field',
    'checkbox_field',
    'radio_field', // Story A.2: Added for AC-A.2.2 (14 field types)
    'rating_field', // Story A.2: Added for AC-A.2.2 (14 field types)
    'textarea_field',
    'gps_field',
    'barcode_field',
    'equipment_diagram_field',
    'tarp_cascade_field',
    'certification_badge_field',
  ];

  /// Parse JSON template and validate schema
  /// Returns TemplateSchema or throws ParseError
  Future<TemplateSchema> parse(String schemaJson) async {
    try {
      final Map<String, dynamic> json = jsonDecode(schemaJson);

      // Validate schema version
      if (!json.containsKey('version')) {
        throw ParseError(
          message: 'Missing required field: version',
          location: 'root',
        );
      }

      final version = json['version'];
      if (!_isVersionCompatible(version)) {
        throw ParseError(
          message: 'Incompatible schema version: $version',
          location: 'root.version',
        );
      }

      // Validate template ID
      if (!json.containsKey('id')) {
        throw ParseError(
          message: 'Missing required field: id',
          location: 'root',
        );
      }

      // Validate sections
      if (!json.containsKey('sections') || json['sections'] is! List) {
        throw ParseError(
          message: 'Missing or invalid sections array',
          location: 'root.sections',
        );
      }

      final sections = <TemplateSection>[];
      final sectionsList = json['sections'] as List;

      for (int i = 0; i < sectionsList.length; i++) {
        try {
          sections.add(_parseSection(sectionsList[i], i));
        } catch (e) {
          if (e is ParseError) {
            rethrow;
          }
          throw ParseError(
            message: 'Failed to parse section: ${e.toString()}',
            location: 'sections[$i]',
          );
        }
      }

      return TemplateSchema(
        id: json['id'],
        version: version,
        name: json['name'] ?? '',
        description: json['description'],
        sections: sections,
      );
    } on FormatException catch (e) {
      throw ParseError(
        message: 'Invalid JSON format: ${e.message}',
        location: 'root',
      );
    } catch (e) {
      if (e is ParseError) rethrow;
      throw ParseError(
        message: 'Failed to parse schema: ${e.toString()}',
        location: 'root',
      );
    }
  }

  /// Parse a section
  TemplateSection _parseSection(Map<String, dynamic> json, int index) {
    if (!json.containsKey('id')) {
      throw ParseError(
        message: 'Missing required field: id',
        location: 'sections[$index]',
      );
    }

    if (!json.containsKey('fields') || json['fields'] is! List) {
      throw ParseError(
        message: 'Missing or invalid fields array',
        location: 'sections[$index].fields',
      );
    }

    final fields = <FieldSchema>[];
    final fieldsList = json['fields'] as List;

    for (int i = 0; i < fieldsList.length; i++) {
      try {
        fields.add(_parseField(fieldsList[i], '$index.$i'));
      } catch (e) {
        if (e is ParseError) {
          rethrow;
        }
        throw ParseError(
          message: 'Failed to parse field: ${e.toString()}',
          location: 'sections[$index].fields[$i]',
        );
      }
    }

    return TemplateSection(
      id: json['id'],
      title: json['title'] ?? '',
      description: json['description'],
      displayOrder: json['display_order'] ?? index,
      fields: fields,
    );
  }

  /// Parse a field
  FieldSchema _parseField(Map<String, dynamic> json, String location) {
    // Validate required fields
    if (!json.containsKey('id')) {
      throw ParseError(
        message: 'Missing required field: id',
        location: 'field[$location]',
      );
    }

    if (!json.containsKey('type')) {
      throw ParseError(
        message: 'Missing required field: type',
        location: 'field[$location].type',
      );
    }

    final type = json['type'];
    if (!supportedFieldTypes.contains(type)) {
      throw ParseError(
        message: 'Unknown field type: $type',
        location: 'field[$location].type',
      );
    }

    // Parse validation rules
    ValidationRules? validation;
    if (json.containsKey('validation')) {
      validation = _parseValidation(json['validation'], location);
    }

    // Parse UI config
    UiConfig? uiConfig;
    if (json.containsKey('ui_config')) {
      uiConfig = _parseUiConfig(json['ui_config']);
    }

    // Parse conditional rules (dependencies)
    List<ConditionalRule>? conditionalRules;
    if (json.containsKey('validation') &&
        json['validation'] is Map &&
        json['validation']['dependencies'] != null) {
      conditionalRules = _parseConditionalRules(
        json['validation']['dependencies'],
        location,
      );
    }
